        "axes[0].plot(surv_family['FamilySize'], surv_family['Survived'],\n",
        "             marker='o', linewidth=2.5, markersize=8, color=ACCENT_BLUE)\n",
        "axes[0].fill_between(surv_family['FamilySize'], surv_family['Survived'],\n",
        "                     alpha=0.15, color=ACCENT_BLUE)\n",
        "axes[0].axhline(38.4, color='gray', linestyle='--', alpha=0.6, label='Overall avg (38.4%)')\n",
